from flask import Flask, render_template, request, redirect, sessionimport sqlite3from flask_bcrypt import Bcryptapp = Flask(__name__)app.secret_key = 'secret123'   # needed for sessionbcrypt = Bcrypt(app)# Create DBdef init_db():    conn = sqlite3.connect('users.db')    conn.execute('CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY, username TEXT, password TEXT)')    conn.close()init_db()# Login Page@app.route('/')def login():    return render_template('login.html')# Signup Page@app.route('/signup')def signup():    return render_template('signup.html')# Register User@app.route('/register', methods=['POST'])def register():    username = request.form['username']    password = request.form['password']    # HASH password    hashed_password = bcrypt.generate_password_hash(password).decode('utf-8')    conn = sqlite3.connect('users.db')    conn.execute("INSERT INTO users (username, password) VALUES (?, ?)", (username, hashed_password))    conn.commit()    conn.close()    return redirect('/')# Login User@app.route('/login', methods=['POST'])def login_user():    username = request.form['username']    password = request.form['password']    conn = sqlite3.connect('users.db')    cursor = conn.execute("SELECT * FROM users WHERE username=?", (username,))    user = cursor.fetchone()    conn.close()    if user and bcrypt.check_password_hash(user[2], password):        session['user'] = username        return redirect('/dashboard')    else:        return "Invalid Credentials ❌"# Dashboard@app.route('/dashboard')def dashboard():    if 'user' in session:        return render_template('dashboard.html', username=session['user'])    else:        return redirect('/')# Logout@app.route('/logout')def logout():    session.pop('user', None)    return redirect('/')if __name__ == '__main__':    app.run(debug=True)